const mongoose = require('mongoose');
const { Schema } = mongoose;

const Author = mongoose.model('Author', new Schema({ name: String, email: String }));
const Post = mongoose.model('Post', new Schema({ title: String, content: String, author: { type: Schema.Types.ObjectId, ref: 'Author' } }));

async function findPostAndPopulateAuthor(postId) {
  await mongoose.connect('mongodb://localhost:27017/myBlog');

  try {
    const post = await Post.findById(postId).populate('author');
    console.log(post);
  } catch (error) {
    console.error('Error:', error.message);
  }

  await mongoose.connection.close();
}

